    // function fix orantek by vitu
    BSS_B2B.printSaveTo = function(shopData) {
        let ruleApplies = [];
        let price = 0;
        if (shopData.product) {
            let variantIdSelected = false;
            if ((BSS_B2B.storeId === 918 || BSS_B2B.storeId === 3918) && $('.product-form__variants').length) {
                variantIdSelected = $('.product-form__variants .no-js.product-form__option select[name=id]').val();
            }

            if (shopData.product) {
                price = parseFloat(shopData.product.price);
            }
            if (variantIdSelected && shopData.product.variants) {
                for (let i = 0; i < shopData.product.variants.length; i++) {
                    let variant = shopData.product.variants[i];
                    if (variant.available && variantIdSelected && variant.id == variantIdSelected) {
                        price = variant.price;
                        break;
                    }
                }
            }
            let element = $('.bss-save-to-cp');
            for (let i = 0; i < BSS_B2B.configData.length; i++) {
                let rule = BSS_B2B.configData[i];
                if (rule.product_condition_type === 0) {
                    ruleApplies.push(rule);
                }
                else if (rule.product_condition_type === 1) {
                    if (rule.product_ids.split(',').includes((shopData.product.id).toString())) {
                        ruleApplies.push(rule);
                    }
                }
                else if (rule.product_condition_type === 2) {
                    if (shopData.collections.filter(
                        item => rule.product_collections.split(',').includes(item.toString())).length) {
                        ruleApplies.push(rule);
                    }
                }
                else if (rule.product_condition_type === 3) {
                    if (shopData.product.tags.filter(
                        item => rule.product_tags.split(',').includes(item.toString())).length) {
                        ruleApplies.push(rule);
                    }
                }
            }
            let priceApplies = [];
            if (ruleApplies.length) {
                let priceApply;
                for (let i = 0; i < ruleApplies.length; i++) {
                    if (ruleApplies[i].discount_type === 0) {
                        priceApply = parseFloat(ruleApplies[i].discount_value);
                        priceApplies.push(priceApply * 100);
                    }
                    else if (ruleApplies[i].discount_type === 1) {
                        priceApply = price - parseFloat(ruleApplies[i].discount_value) * 100;
                        priceApplies.push(priceApply);
                    }
                    else if (ruleApplies[i].discount_type === 2) {
                        priceApply = price - price * parseFloat(ruleApplies[i].discount_value) / 100;
                        priceApplies.push(priceApply);
                    }
                }

                let bestPrice = Math.min.apply(Math, priceApplies);
                element.html(BSS_B2B.formatMoney(bestPrice));
                $('.bss-custom').css({'visibility': 'visible'});
            }
        }
    };

    BSS_B2B.checkExcludeCustomer = function(rule) {
        let excludeCustomerTags = rule.exc_customer_tags;
        let excludeFrom = rule.exclude_from ? parseInt(rule.exclude_from) : null;
        let excludeCustomers = rule.exc_customers;
        if (excludeFrom === 1) {
            if (excludeCustomerTags && excludeCustomerTags.length && shopData.customer.tags !== null) {
                excludeCustomerTags = excludeCustomerTags.split(',');
                let checkArray = excludeCustomerTags.filter(tag => shopData.customer.tags.includes(tag.toLowerCase() + ''));
                if (checkArray.length > 0) {
                    return true;
                }
            }
        }
        else if (excludeFrom === 2) {
            if (excludeCustomers) {
                if (excludeCustomers.includes(`${shopData.customer.id}`)) {
                    return true;
                }
            }
        }
        return false;
    }

    BSS_B2B.checkAppliedTo = function(rule){
        let applyTo = rule.apply_to;
        let customerIds = rule.customer_ids;
        let customerTags = rule.customer_tags;
        let listStoreId = [918, 2709, 3918];
        if (applyTo === 1) {
            if (shopData.customer.id == null) {
                if (listStoreId.indexOf(BSS_B2B.storeId) !== -1) {
                    //fix orantek and wilberrys by vitu
                    BSS_B2B.printSaveTo(shopData);
                }
                return false;
            }
        }
        else if (applyTo === 2) {
            if (shopData.customer.id !== null) {
                return false;
            }
            else {
                if (listStoreId.indexOf(BSS_B2B.storeId) !== -1) {
                    //fix orantek and wilberrys by vitu
                    BSS_B2B.printSaveTo(shopData);
                }
            }
        }
        else if (applyTo === 3) {
            if (shopData.customer.id == null) {
                if (listStoreId.indexOf(BSS_B2B.storeId) !== -1) {
                    //fix orantek and wilberrys by vitu
                    BSS_B2B.printSaveTo(shopData);
                }
                return false;
            }
            else {
                customerIds = customerIds ? customerIds.split(',') : [];
                if (customerIds.indexOf(shopData.customer.id + '') === -1) {
                    return false;
                }
            }
        }
        else if (applyTo === 4) {
            if (shopData.customer.tags == null) {
                if (listStoreId.indexOf(BSS_B2B.storeId) !== -1) {
                    //fix orantek and wilberrys by vitu
                    BSS_B2B.printSaveTo(shopData);
                }
                return false;
            }
            else {
                customerTags = customerTags.split(',');
                // to lower case
                shopData.customer.tags = shopData.customer.tags.map((tag) => tag.toLowerCase());
                customerTags = customerTags.map((tag) => tag.toLowerCase());
                let checkArray = customerTags.filter((tag) => shopData.customer.tags.includes(tag + ''));
                if (checkArray.length === 0) {
                    if (listStoreId.indexOf(BSS_B2B.storeId) !== -1) {
                        //fix orantek and wilberrys by vitu
                        BSS_B2B.printSaveTo(shopData);
                    }
                    return false;
                }
            }
        }
        return true
    }

    BSS_B2B.checkAppliedDate = function(rule) {
        let startDate = rule.start_date;
        let endDate = rule.end_date;
        let currentDate = new Date();
        if (startDate && currentDate < new Date(startDate)) {
            return false;
        }
        if (endDate && currentDate > new Date(endDate)) {
            return false;
        }
        return true
    }

    BSS_B2B.checkAppliedMarket = function(rule) {
        let marketConditionType = rule.market_condition_type;
        let allowedRegions = rule.allowed_regions;

        if (marketConditionType === 1) {
            if (allowedRegions && allowedRegions.length && !allowedRegions.includes(Shopify.country)) {
                return false;
            }
        }
        return true;
    }

    BSS_B2B.checkAppliedPLRule = function(rule) {
        if(BSS_B2B.checkExcludeCustomer(rule)){
            return false;
        } 

        if(!BSS_B2B.checkAppliedTo(rule)){
            return false;
        }

        if(!BSS_B2B.checkAppliedDate(rule)){
            return false;
        }
        return true;
    }

    BSS_B2B.checkAppliedCPRule = function(rule) {
        if(!BSS_B2B.checkAppliedMarket(rule)) {
            return false;
        }

        if(!BSS_B2B.checkAppliedTo(rule)){
            return false;
        }

        if(!BSS_B2B.checkAppliedDate(rule)){
            return false;
        }

        if(BSS_B2B.checkExcludeCustomer(rule)){
            return false;
        }

        return true;
    }

    BSS_B2B.getPriceList = function(shopData, productMap, isCartItem, productPrices) {
        if (
            !isEnableCP || (!BSS_B2B.configData && !BSS_B2B.plConfigData)
            || (BSS_B2B.configData.length === 0 && BSS_B2B.plConfigData.length === 0)
        ) {
            return [];
        }
        let productPriceListMap = new Map();
        let variantPriceListMap = new Map();
        let cartItemPriceListMap = new Map();
        let priceMinMap = new Map()
        let ruleList = BSS_B2B.configData;
        let plRuleList = BSS_B2B.plConfigData;
        let checkAppliedProduct = [];
        let checkAppliedVariant = [];
        let productApplied;
        const ruleTypes = {
            CP: 'CP',
            PL: 'PL',
        };

        plRuleList && plRuleList.forEach((rule) =>{
            if(!BSS_B2B.checkAppliedPLRule(rule)){
                return;
            }
            for (let i = 0; i < productMap.length; i++) {
                let productId = productMap[i].id;
                let cartKey = isCartItem ? productMap[i].key : false;
                let isFeatured = productMap[i].isFeatured ? true : false
                let variantSelectedId = productMap[i].variantsApplied ? productMap[i].variantsApplied : null;



                if(rule.apply_at) {
                    let selectedVariants = rule.selected_variants;
                    let priceList = {
                        'id': productId,
                        'rule_id': rule.id,
                        'key': cartKey,
                        'name': rule.name,
                        'ruleType': ruleTypes.PL,
                    }
                    if(variantSelectedId){
                        if(isFeatured) {
                            let variantAppliedPL = selectedVariants.find((item) => parseInt(item.variant_id) === variantSelectedId)
                            if(variantAppliedPL) {
                                let variantAppliedId = variantAppliedPL.variant_id;
                                priceList = {
                                    ...priceList,
                                    'discount_type': variantAppliedPL.discount_type,
                                    'value': variantAppliedPL.discount_value,
                                    'pid': variantAppliedPL.id,
                                    'sid': `${variantAppliedPL.token}.${Buffer.from(String(cartKey)).toString('base64')}`,
                                }
                                
                                if(!variantPriceListMap.get(parseInt(variantAppliedId))) {
                                    variantPriceListMap.set(parseInt(variantAppliedId),{
                                        ...priceList,
                                        'isFeatured': true,
                                        'variantSelected': parseInt(variantAppliedId),
                                    })
                                }
                            } else {
                                let productVariantApplied = selectedVariants.find((item) => parseInt(item.product_id) === productId)
                                if(productVariantApplied) {
                                    checkAppliedProduct.push(parseInt(productVariantApplied.product_id));
                                }
                            }
                        } if(isCartItem) {
                            let appliedCartItem = selectedVariants.filter((item) => variantSelectedId.includes(parseInt(item.variant_id)) && parseInt(item.product_id)=== productId);
                            if(appliedCartItem.length > 0){
                                for(const item of appliedCartItem){
                                    if(!cartItemPriceListMap.get(parseInt(item.variant_id))){
                                        if(!checkAppliedProduct.includes(parseInt(item.product_id))){
                                            checkAppliedProduct.push(parseInt(item.product_id))
                                        }
                                        cartItemPriceListMap.set(parseInt(item.variant_id), {
                                            ...priceList,
                                            'discount_type': item.discount_type,
                                            'value': item.discount_value,
                                            'pid': item.id,
                                            'sid': `${item.token}.${Buffer.from(String(cartKey)).toString('base64')}`,
                                            'variants': [item.variant_id]
                                        })
                                    }
                                }
                            }
                        } 
                        if(checkAppliedProduct.length > 0){
                            checkAppliedProduct.forEach((item) => {
                                if(!productPriceListMap.get(item)) {
                                    productPriceListMap.set(item, true)
                                }
                            })
                        }
                    } else {
                        const productData = productPrices[productId];
                        if(!priceMinMap.get(productId)) {
                            priceMinMap.set(productId, {
                                priceMinProductAfterApplyPL: productData.price,
                                selectedVariant: null
                            })
                        }
                        productApplied = selectedVariants.reduce((priceMinMapApplied, product) => {
                            let proId = parseInt(product.product_id);
                            let variantId = parseInt(product.variant_id);
                            if(proId == productId && !checkAppliedVariant.includes(variantId)) {
                                let priceMin = priceMinMapApplied.get(productId);
                                checkAppliedVariant.push(variantId);
                                let variantData = productData.variants.find((item) => item.id === variantId)
                                let priceAppliedPL = BSS_B2B.getModifiedPrice(
                                    variantData.price, 
                                    product.discount_type, 
                                    parseFloat(product.discount_value)
                                )
                                if(priceAppliedPL < priceMin.priceMinProductAfterApplyPL) {
                                    priceMinMapApplied.set(productId, {
                                        priceMinProductAfterApplyPL: priceAppliedPL,
                                        selectedVariant: {
                                            'id': productId,
                                            'rule_id': rule.id,
                                            'discount_type': product.discount_type,
                                            'value': product.discount_value,
                                            'key': cartKey,
                                            'name': rule.name,
                                            'ruleType': ruleTypes.PL,
                                            'pid': product.id,
                                            'sid': `${product.token}.${Buffer.from(String(cartKey)).toString('base64')}`, 
                                            'variants': parseInt(product.variant_id),
                                        }
                                    })
                                }
                            }
                            return priceMinMapApplied;
                        },priceMinMap)

                        if(productApplied && productApplied.size > 0) {
                            productApplied.forEach((priceList, key) => {
                                if(priceList.selectedVariant && !productPriceListMap.get(key)) {
                                    productPriceListMap.set(key, priceList.selectedVariant)
                                }
                            })
                        }
                    }
                } else {
                    let prods = rule.selected_products.filter(product => {
                        let prodId = parseInt(product.product_id);
                        return productId === prodId
                    });
                    if (prods.length > 0) {
                        let priceList = {
                            'id': productId,
                            'rule_id': rule.id,
                            'discount_type': prods[0].discount_type,
                            'value': prods[0].discount_value,
                            'key': cartKey,
                            'name': rule.name,
                            'ruleType': ruleTypes.PL,
                            'pid': prods[0].id,
                            'sid': `${prods[0].token}.${Buffer.from(String(cartKey)).toString('base64')}`,
                        }
                        if(productMap[i].variantsApplied) {
                            if(productMap[i].isFeatured) {
                                if(!variantPriceListMap.get(parseInt(productMap[i].variantsApplied))) {
                                    variantPriceListMap.set(parseInt(productMap[i].variantsApplied), {
                                        ...priceList,
                                        'isFeatured': true,
                                        'variantSelected': productMap[i].variantsApplied,
                                    })
                                }
                            } else if(isCartItem) {
                                if(!cartItemPriceListMap.get(cartKey)) {
                                    cartItemPriceListMap.set(cartKey, priceList);
                                }
                            }
                        } else {
                            const productData = productPrices && productPrices[productId];
                            if(productData) {
                                let priceProduct = productData.variants.reduce((oldValue, currentValue) => (
                                    currentValue < oldValue ? currentValue : oldValue
                                ), productData.variants[0].price)
                                const priceMin = priceMinMap.get(productId) ? priceMinMap.get(productId).priceMinProductAfterApplyPL : null;
                                const priceApplyPLProduct = BSS_B2B.getModifiedPrice(
                                    priceProduct, 
                                    prods[0].discount_type, 
                                    parseFloat(prods[0].discount_value)
                                )
                                if(priceMin && priceApplyPLProduct < priceMin) {
                                    productPriceListMap.set(productId, priceList);
                                } else {
                                    if(!productPriceListMap.get(productId)){
                                        productPriceListMap.set(productId, priceList);
                                    }
                                }
                            }
                        }
                    }
                }
            }
        })

        // for(const id of productPriceListMap.keys()){
        //     if(productPrices){
        //         let productData = productPrices[parseInt(id)];
        //         if(productData) {
        //             let variants = productData.variants.map((item) => item.id);
        //             variants.forEach(variant => {
        //                 if(!variantPriceListMap.get(variant)) {
        //                     variantPriceListMap.set(variant, true)
        //                 }
        //             })
        //         }
        //     }
        // }
        //end check PL rules

        checkAppliedProduct = [];
        productApplied = null;
        // priceMinMap = new Map();

        //start check CP rule

        ruleList && ruleList.forEach(function(rule) {
            if(!BSS_B2B.checkAppliedCPRule(rule)){
                return
            }

            let conditionType = rule.product_condition_type;
            let ruleTags = rule.product_tags ? rule.product_tags.split(',').map((tag) => tag.toLowerCase()) : [];
            let specificProductIds = rule.product_ids ? rule.product_ids.split(',') : [];
            let ruleCollectionIds = rule.product_collections ? rule.product_collections.split(',') : [];
            let productVariantIds = rule.product_variants ? rule.product_variants.split(',') : [];
            for (let i = 0; i < productMap.length; i++) {
                const productId = productMap[i].id;
                const variantSelectedId = productMap[i].variantsApplied;
                const productTitle = productMap[i].product_name;
                const isFeatured = productMap[i].isFeatured;
                const cartKey = isCartItem ? productMap[i].key : false;
                const collections = productMap[i].collections || [];
                const tags = productMap[i].tags ? productMap[i].tags.map((tag) => tag.toLowerCase()) : [];
                let isApplied = false;

                let priceList = {
                    'id': productId,
                    'discount_type': rule.discount_type,
                    'value': rule.discount_value,
                    'key': cartKey,
                    'name': rule.name,
                    'product_name': productTitle,
                    'ruleType': ruleTypes.CP,
                    'rule_id': rule.id,
                    'sid': `${rule.token}.${Buffer.from(String(cartKey)).toString('base64')}`,
                }

                if(conditionType === 4 && BSS_B2B.planCode === "platinum") {
                    if(variantSelectedId) {
                        if (isFeatured) {
                            let checkArray = productVariantIds.find((item) => parseInt(item) === variantSelectedId)
                            if (checkArray && !variantPriceListMap.get(parseInt(checkArray))) {
                                variantPriceListMap.set(parseInt(checkArray), {
                                    ...priceList,
                                    'isFeatured': true,
                                    'variantSelected': variantSelectedId,
                                })
                            } else {
                                const selectedVariants = productPrices[productId].variants;
                                const productVariantApplied = selectedVariants.find((item) => productVariantIds.includes(item.toString()))
                                if(productVariantApplied) {
                                    checkAppliedProduct.push(productId);
                                }
                            }
                        } else if(isCartItem) {
                            let checkArray = productVariantIds.filter((variant) => variantSelectedId.includes(parseInt(variant)));
                            if (checkArray && checkArray.length > 0 ){
                                for(const item of checkArray) {
                                    if(!cartItemPriceListMap.get(parseInt(item))){
                                        cartItemPriceListMap.set(parseInt(item), {
                                            ...priceList,
                                            "variants": [item]
                                        })
                                    }
        
                                }
                            }
                        }
                        if(checkAppliedProduct.length > 0){
                            checkAppliedProduct.forEach((item) => {
                                if(!productPriceListMap.get(item)) {
                                    productPriceListMap.set(item, true)
                                }
                            })
                        }
                    } else {
                        //Handle apply price to selected variant in card product
                        const productData = productPrices[productId];
                        if(!priceMinMap.get(productId)) {
                            priceMinMap.set(productId, {
                                priceMinProductAfterApplyPL: productData.price,
                                selectedVariant: null
                            })
                        }
                        productApplied = productVariantIds.reduce((priceMinMapApplied, variants) => {
                            let variantId = parseInt(variants);
                            let variantsProduct = productData.variants.find((item) => item.id === variantId && !checkAppliedVariant.includes(item.id))
                            if(variantsProduct) {
                                let priceMin = priceMinMapApplied.get(productId);
                                checkAppliedVariant.push(variantId);
                                let variantData = productData.variants.find((item) => item.id === variantId)
                                let priceAppliedPL = BSS_B2B.getModifiedPrice(
                                    variantData.price, 
                                    rule.discount_type, 
                                    parseFloat(rule.discount_value)
                                )
                                if(priceAppliedPL < priceMin.priceMinProductAfterApplyPL) {
                                    priceMinMapApplied.set(productId, {
                                        priceMinProductAfterApplyPL: priceAppliedPL,
                                        selectedVariant: {
                                            'id': productId,
                                            'rule_id': rule.id,
                                            'discount_type': rule.discount_type,
                                            'value': rule.discount_value,
                                            'key': cartKey,
                                            'name': rule.name,
                                            'ruleType': ruleTypes.CP,
                                            'pid': rule.id,
                                            'sid': `${rule.token}.${Buffer.from(String(cartKey)).toString('base64')}`, 
                                            'variants': parseInt(variantId),
                                        }
                                    })
                                }
                            }
                            return priceMinMapApplied;
                        },priceMinMap)

                        if(productApplied && productApplied.size > 0) {
                            productApplied.forEach((priceList, key) => {
                                if(priceList.selectedVariant && !productPriceListMap.get(key)) {
                                    productPriceListMap.set(key, priceList.selectedVariant)
                                }
                            })
                        }
                    }
                } else {
                    if (conditionType === 0) {
                        isApplied = true;
                    }
                    else if (conditionType === 1) {
                        if (specificProductIds.indexOf(productId + '') !== -1) {
                            isApplied = true;
                        }
                    }
                    else if (conditionType === 2) {
                        let checkArray = collections ? collections.filter(
                            collection => ruleCollectionIds.includes(collection + '')) : [];
                        if (checkArray.length > 0) {
                            isApplied = true;
                        }
                    }
                    else if (conditionType === 3) {
                        let checkArray = ruleTags.filter(tag => tags.includes(tag));
                        if (checkArray.length > 0) {
                            isApplied = true;
                        }
    
                    }
                    if(isApplied) {
                        if(productMap[i].variantsApplied){
                            if(productMap[i].isFeatured) {
                                if(!variantPriceListMap.get(variantSelectedId)) {
                                    variantPriceListMap.set(variantSelectedId, {
                                        ...priceList,
                                        'isFeatured': true,
                                        'variantSelected': variantSelectedId,
                                    })
                                }
                            } else if(isCartItem) {
                                if(!cartItemPriceListMap.get(cartKey)){
                                    cartItemPriceListMap.set(cartKey, priceList)
                                }
                            }
                        } else {
                            const productData = productPrices[productId];
                            if(productData) {
                                let priceProduct = productData.variants.reduce((oldValue, currentValue) => (
                                    currentValue < oldValue ? currentValue : oldValue
                                ), productData.variants[0].price)
                                const priceMin = priceMinMap.get(productId) ? priceMinMap.get(productId).priceMinProductAfterApplyPL : null;
                                const priceApplyPLProduct = BSS_B2B.getModifiedPrice(
                                    priceProduct, 
                                    rule.discount_type, 
                                    parseFloat(rule.discount_value)
                                )
                                if(priceMin && priceApplyPLProduct < priceMin) {
                                    productPriceListMap.set(productId, priceList);
                                } else {
                                    if(!productPriceListMap.get(productId)){
                                        productPriceListMap.set(productId, priceList);
                                    }
                                }
                            }
                        }
                    }
                }
            }
        });

        // for(const id of productPriceListMap.keys()){
        //     if(productPrices){
        //         let productData = productPrices[parseInt(id)];
        //         if(productData) {
        //             let variants = productData.variants.map((item) => item.id);
        //             variants.forEach(variant => {
        //                 if(!variantPriceListMap.get(variant)) {
        //                     variantPriceListMap.set(variant, true)
        //                 }
        //             })
        //         }
        //     }
        // }

        // end check CP rules

        let priceLists = [];
        if(!isCartItem) {
            for(const value of [...productPriceListMap.values(), ...variantPriceListMap.values()]) {
                if(!(value === true)) {
                    priceLists.push(value);
                }
            }
        } else {
            priceLists = [...cartItemPriceListMap.values()]
        }
        return priceLists;
    };

    BSS_B2B.getModifiedPrice = function(price, type, discountValueOfRule) {
        let modifiedPrice = price;
        let rateMarket = Shopify.currency.rate;
        let discountValueWithMarket = BSS_B2B.helper.convertPriceWithRate(discountValueOfRule) * 100;
        if (type === 0) {
            let priceWithStoreCurrency = price / rateMarket;

            discountValueOfRule = discountValueOfRule * 100;
            if (priceWithStoreCurrency > discountValueOfRule) {
                let realDiscount = (priceWithStoreCurrency - discountValueOfRule) / 100;
                realDiscount = realDiscount.toFixed(2);
                realDiscount = (realDiscount * rateMarket);
                realDiscount = realDiscount.toFixed(2);
                realDiscount = realDiscount * 100;

                modifiedPrice = Math.round((price - realDiscount) * 100) / 100;
            }
            else {
                modifiedPrice = price;
            }
        }
        else if (type === 1) {
            modifiedPrice = discountValueWithMarket > price ? 0 : (price - discountValueWithMarket);
        }
        else if (type === 2) {
            let realDiscountValueItem = (price / rateMarket) * (discountValueOfRule / 100);
            realDiscountValueItem = realDiscountValueItem.toFixed(0);
            realDiscountValueItem = (realDiscountValueItem * rateMarket).toFixed(0);

            modifiedPrice = price - realDiscountValueItem;

            // fix for canicoolhq by Leorio
            // if (BSS_B2B.storeId === 1508 && BSS_B2B.page.isCartPage()) {
            //     if (modifiedItemPrice % 0.5 === 0) {
            //         modifiedPrice = Math.round(modifiedPrice);
            //     }
            // }
        }

        return modifiedPrice;
    };

    BSS_B2B.checkVariantExist = function(cartFormElement, variant) {
        let cartFormId = $(cartFormElement).attr('id');
        let cartFormIdNumber = '';
        if (cartFormId !== undefined) {
            cartFormIdNumber = cartFormId.replace(/\W/g, '');
        }
        let selectedVariant = $(cartFormElement).find('select#ProductSelect--product-template :selected, ' +
            'select#ProductSelect--featured-product :selected, ' +
            'select[name="id"] :selected, ' +
            'select[id$="' + cartFormIdNumber + '"] :selected'
            + BSS_B2B.getCssSelector('product_select_variant_input'),
        );
        if (selectedVariant.length) {
            let selectedVariantId = selectedVariant.val();
            if (selectedVariantId == variant.id) {
                return true;
            }
            else {
                return false;
            }
        }
        return true;
    };

