function checkout_fixModules(app) {
    const fixHandleCartCheckoutBtn = (shopData, checkoutButton) => {
        // fix for storeID 4576
        window.BSS_B2B.executeAction({tag: 'customize_validate_te', storeId: 4576, shopData})

        if (BSS_B2B.storeId === 2709) {
            // fix wilberrys by vitu
            $(this).off();
        }
        if (BSS_B2B.storeId === 3787) {
            if (shopData.customer.id == null) {
                return;
            }
        }

        if (BSS_B2B.storeId === 6767) {
            $(this).off();
            let checkOutPopupButton = document.querySelector('.popup_cart .cart-popup-action .btn.btn-danger');
            if (checkOutPopupButton) {
                checkOutPopupButton.removeAttribute('onclick');
            }
        }
        // fix for storeID 4324
        window.BSS_B2B.executeAction({tag: 'customize_validate_te', storeId: 4324, checkoutButton, shopData})
        if (BSS_B2B.storeId === 4945) {
            $(document).on('submit', 'form.js-cart-form', function () {
                return false;
            });
        }
        if (BSS_B2B.storeId === 7056) {
            checkoutButton.css({
                'pointer-events': 'auto',
                'opacity': '1'
            })
            checkoutButton.removeAttr('disabled')
        }
        if ([7795, 7259].includes(BSS_B2B.storeId)) {
            checkoutButton.addClass("bss-checkout-event");
        }

        if ([9568, 10085, 9461, 7259, 13344].includes(BSS_B2B.storeId)) {
            if (checkoutButton && jQuery && checkoutButton instanceof jQuery) {
                checkoutButton.off();
                checkoutButton.removeAttr('onclick');
            }
        }
        if ([13344].includes(BSS_B2B.storeId)) {
            checkoutButton.attr("bss-b2b-custom-checkout-btn", "")
        }
        //fix ichi store by trung dd
        if (BSS_B2B.storeId === 11149) {
            setTimeout(() => {
                checkoutButton.removeClass("bss-b2b-custom-checkout-disable");
            }, 1000)
        }

        if(BSS_B2B.storeId === 10989){
            if (checkoutButton && jQuery && checkoutButton instanceof jQuery && BSS_B2B.cpSettings) {
                checkoutButton.removeAttr('name');
            }
        }
        if(BSS_B2B.storeId === 11378) {
            setTimeout(() =>{
                const isAddedEvent = checkoutButton.attr(`bss-b2b-added-event`);
                if(!isAddedEvent) {
                    BSS_B2B.handleCartCheckoutBtn(shopData);
                }
                let buttonCheckouts = document.querySelectorAll(BSS_B2B.helper.checkoutElements);
                buttonCheckouts.forEach((buttonCheckoutElem) => {
                    buttonCheckoutElem.setAttribute('bss-b2b-added-event', 'true');
                    buttonCheckoutElem.style.display = 'inline-block';
                });
            }, 2000);
        }
    }

    app.fix.checkout = {
        fixHandleCartCheckoutBtn
    };
}

