// CONCATENATED MODULE: ./js/src/cart/observingCartChange.js
class CartWatcher {
    init() {
        this.emitCartChanges().then(() => {
            this.observeCartChanges();
        });
    }

    async fetchCart() {
        const response = await fetch('/cart.js');
        return response.json();
    }

    storeCart(cart) {
        localStorage.setItem('cart', JSON.stringify(cart));
    }

    storedCart() {
        return JSON.parse(localStorage.getItem('cart')) || { items: [] };
    }

    findCartChanges(oldCart, newCart) {
        const findOnlyChange = (oldItems, newItems) => oldItems.filter(oldItem => !newItems.some(newItem => oldItem.key == newItem.key));

        let result = {
            added: findOnlyChange(newCart.items, oldCart.items),
            removed: findOnlyChange(oldCart.items, newCart.items),
        };

        oldCart.items.forEach(oldItem => {
            const newItem = newCart.items.find(item => item.key == oldItem.key && item.quantity != oldItem.quantity);
            if (!newItem) return;
            let quantity = newItem.quantity - oldItem.quantity;
            let item = { ...newItem };
            item.quantity = Math.abs(quantity);
            quantity > 0
                ? result.added.push(item)
                : result.removed.push(item)
        });

        return result;
    }

    async emitCartChanges() {
        const newCart = await this.fetchCart();
        const oldCart = this.storedCart();
        const changes = this.findCartChanges(oldCart, newCart);

        const event = new CustomEvent("cart_changed", { detail: changes });
        window.dispatchEvent(event);

        this.storeCart(newCart);
    }

    observeCartChanges() {
        const cartObserver = new PerformanceObserver((list) => {
            list.getEntries().forEach((entry) => {
                const isValidRequestType = ['xmlhttprequest', 'fetch'].includes(entry.initiatorType);
                const isCartChangeRequest = /\/cart\//.test(entry.name);
                if (isValidRequestType && isCartChangeRequest) {
                    this.emitCartChanges();
                }
            });
        });
        cartObserver.observe({ entryTypes: ["resource"] });
    }
}
