    BSS_B2B.RF.renderReCAPCHA = function () {
        const dataSiteKey = BSS_B2B.CAPCHA_SITE_KEY;
        let submitBtn = $(closestForm).find('[type=submit]');
        //fix moosecreekscreenprintdesigns by hoaduong
        if (submitBtn.length === 0 && BSS_B2B.storeId === 4250) {
            submitBtn = $(closestForm).find('button');
        }
        if (submitBtn.length === 0) {
            let defaultForm = $('#bss-b2b-registration-form-render').closest('form#create_customer');
            if (defaultForm.length) {
                submitBtn = $(closestForm).find('button');
            }
        }
        if (submitBtn.length) {
            if (BSS_B2B.storeId === 3404) {
                $(submitBtn).parent().parent().before(`<div class="g-recaptcha" data-sitekey="${dataSiteKey}" data-callback="correctCaptcha"></div>`);
            } else {
                $(submitBtn).before(`<div class="g-recaptcha" data-sitekey="${dataSiteKey}" data-callback="correctCaptcha"></div>`);
            }
            let bssB2BLoadScript = function (url, callback) {
                let script = document.createElement("script");
                script.type = "text/javascript";
                // If the browser is Internet Explorer.
                if (script.readyState) {
                    script.onreadystatechange = function () {
                        if (script.readyState === "loaded" || script.readyState === "complete") {
                            script.onreadystatechange = null;
                            callback();
                        }
                    };
                    // For any other browser.
                } else {
                    script.onload = function () {
                        callback();
                    };
                }

                script.src = url;
                document.getElementsByTagName("head")[0].appendChild(script);

            };
            bssB2BLoadScript('https://www.google.com/recaptcha/api.js', function () {
                $(submitBtn).on('click', function (e) {
                    const storeId = BSS_B2B.storeId;
                    if (BSS_B2B.storeId === 3576) {
                        let storeGroupElem = document.getElementById('select-1648015104934');
                        if (storeGroupElem) {
                            if (storeGroupElem.value === 'option-1') storeGroupElem.value = '';
                        }
                        if (!$(closestForm)[0].checkValidity()) {
                            $(closestForm)[0].reportValidity();
                            return;
                        }
                    }
                    e.preventDefault();
                    const recaptchaRes = $('[name=g-recaptcha-response]').val();
                    $('.reCAPCHA-err').remove();
                    if(sessionStorage.getItem("verifyCaptcha") && recaptchaRes) {
                        $(submitBtn).submit();
                    } else {
                        $.ajax({
                            type: "POST",
                            url: bssB2bApiServer + '/recapcha/verify',
                            dataType: 'JSON',
                            data: {
                                'domain': Shopify.shop,
                                'g-recaptcha-response': recaptchaRes,
                                'store_id': storeId
                            },
                            success: function (result) {
                                if (result.success) {
                                    $('.reCAPCHA-err').remove();
                                    sessionStorage.setItem("verifyCaptcha", "true")
                                    setTimeout(() =>{
                                        sessionStorage.removeItem("verifyCaptcha")
                                    }, 50000)
                                    $(submitBtn).submit();
                                } else {
                                    const complete_reCapcha_task_translation = utilities_default.a.checkRFGeneralSettings('complete_reCapcha_task', 'Please complete reCAPTCHA task');
                                    const content = `<p class="reCAPCHA-err" style="color: ${textColorFail}; text-align: center; margin-bottom: 10px;">`
                                        + '<span class="bss-b2b-translation-rf-complete_reCapcha_task">' + complete_reCapcha_task_translation + '</span>'
                                        + `</p>`;
                                    $(submitBtn).before(content);
                                }
                                $('.bss-loading-msg').remove();
                            },
                            error: function (XMLHttpRequest, textStatus, errorThrown) {
                                const content = `<p class="reCAPCHA-err" style="color: ${textColorFail}; text-align: center; margin-bottom: 10px;">${XMLHttpRequest.status} ${textStatus}: ${errorThrown}</p>`;
                                $(submitBtn).before(content);
                            }
                        });
                    }
                    
                });
                let correctCaptcha = function (response) {
                    if (response.length) {
                        $('.reCAPCHA-err').remove();
                    }
                };
                window.correctCaptcha = correctCaptcha;
            });
        }
    };
    BSS_B2B.RF.renderPrivacyPolicy = function () {
        let submitBtn = $(closestForm).find('[type=submit]');
        let formRenderBottom = $('#bss-b2b-registration-form-render');
        if (BSS_B2B.formPrivacyPolicyContent.length) {
            const content = `<div class='bss_rf_privacy_policy_container'><input type="checkbox" id="bss_rf_privacy_policy" name="bss_rf_privacy_policy"> <label for="bss_rf_privacy_policy">${BSS_B2B.formPrivacyPolicyContent}</label></div>`;
            if (submitBtn.length) {
                $(submitBtn).before(content);
            } else if (formRenderBottom.length) {
                $(formRenderBottom).after(content);
            }
        }
    };

