                            if (![6318, 8841].includes(BSS_B2B.storeId)) {
                                note += `===end custom fields by bss-b2b-rf=== \n`;
                            }
                            // fix for metrio.eu by mitri
                            if (BSS_B2B.storeId === 1445) {
                                let euVat = note.match(/[A-Z]{2}\w+\d/);
                                note = euVat && euVat.length ? euVat[0] : note;
                            }

